var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제1 방위선, 거점 기지","JPN":"人類統合防衛軍第1防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 1st Defense Line","TWN":"人類共同保衛軍第一防線基地"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"제3차 아포리아 공략 작전","JPN":"第3次アポリア攻略作戦","ENG":"Operation Aporia, 3rd attempt","TWN":"第三波攻陷阿波利亞作戰"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"최종 결전이라는 말을 듣기는 했는데…….","JPN":"最終決戦とは聞いていたけど……","ENG":"I did hear that this was going to be the final battle...","TWN":"我聽說這就是最終決戰了……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"모, 못 본 사이에 뭔가 많이 달라진 것 같은데, 소령?","JPN":"み、見ない間に何だかだいぶ変わったわね、少佐？","ENG":"B-but you seemed to have changed a lot, Major.","TWN":"一陣子不見，你變了不少呢，少校？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아이기스의 마스터 코드는 내 오른쪽 눈에 깃들어 있네.","JPN":"アイギスのマスターコードは私の右眼に組み込まれている。","ENG":"The master code of Aegis is embedded in my right eye.","TWN":"埃癸斯的管理代碼藏在我右眼裡。"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"오른쪽 눈?","JPN":"右眼？","ENG":"Your right eye?","TWN":"右眼？"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"고유 무장, <color=#ffd34c>글라우코피스</color>.","JPN":"固有武装、<color=#ffd34c>グラウコーピス</color>。","ENG":"Unique Gear, <color=#ffd34c>Glaukopis</color>.","TWN":"專屬裝備<color=#ffd34c>雅典娜</color>。"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"의안 형태의 이 고유 무장은 우리 같은 분석 능력자의 연산 출력을 극적으로 끌어올려주지.","JPN":"義眼の形状をしたこの武装は、我々のような分析能力者の演算能力を劇的に引き上げてくれる。","ENG":"This Unique Gear, in the form of an artificial eye, dramatically increases the calculation output of analytical abilities similar to our own.","TWN":"義眼形態的專屬裝備，可以極大化我們這類分析者的運算輸出。"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"또한 아이기스의 모든 시스템은 글라우코피스 사용자의 CRF에만 반응하도록 설계되어 있어.","JPN":"また、アイギスのすべてのシステムはグラウコーピス使用者のCRFにのみ反応するよう設計されている。","ENG":"Also, all systems of Aegis are designed to respond exclusively to the CRF of the Glaukopis user.","TWN":"埃癸斯的所有系統都設計成只會對雅典娜使用者的CRF做出反應。"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"역으로 말하면 고유 무장을 이식하는 순간, 자네는 살아있는 채로 아이기스의 일부가 되는 거야.","JPN":"逆に言えば、固有武装を移植した瞬間、君は生きたままアイギスの一部になるんだ。","ENG":"In other words, the moment you get this Unique Gear implanted, you will be a part of Aegis as long as you live.","TWN":"反過來說，專屬裝備移植成功的那瞬間，你只要活著，就一直是埃癸斯的一部分。"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"따라서 고유 무장을 인계받은 자네가 죽으면, 우리 세계의 유산은 분자단위로 사라져버리겠지.","JPN":"つまり、固有武装を引き継いだ君が死亡すれば、我々の世界の遺産は分子単位に分解され消滅してしまうということだな。","ENG":"Accordingly, if you die with the Unique Gear, all our legacy will be disintegrated at a molecular level.","TWN":"所以，如果繼承專屬裝備的你死去，我們世界的遺產就會徹底分解消失。"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네에게 그걸 짊어질 각오가 있다면, 이 눈 자네에게 넘겨주겠네.","JPN":"君にそれを背負う覚悟があるなら、この眼は君に渡そう。","ENG":"If you are determined to take this risk, I shall hand the eye over to you.","TWN":"如果你有覺悟承擔這份責任，我就把這隻眼睛交給你。"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그래서 뭐가 어떻게 된 건데?","JPN":"それで、なにがどうなってるの？","ENG":"So, what's gonna happen?","TWN":"所以，到底是怎麼回事？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"간단히 요약하면, 이 로스트 쉽과 함의 무기고를 사용할 수 있게 되었어요.","JPN":"簡単に言えば、このロストシップと船の武器庫を使えるようになりました。","ENG":"Simply put, we have gained access to this Lost Ship and its arsenal.","TWN":"簡單來說，這艘失落艦船和武器庫已經可以使用了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그게 정말이야? 이 함선의 프로텍트는 생전 처음 보는 패턴이었다고!","JPN":"それって本当？　この艦船のプロテクトは生まれて初めて見るパターンだったのよ！","ENG":"Really? But I've never seen a protection pattern like this ship's!","TWN":"真的嗎？這艘艦船的防禦模式我還是第一次見到！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그걸 하루아침에 뚫었어? 어떻게?","JPN":"それを一晩で突破した？　どうやって？","ENG":"But you cracked it in just one day? How?","TWN":"你這麼快就辦到了？怎麼做到的？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"자세한 건 나중에 설명해드리죠.","JPN":"詳しいことは後で説明します。","ENG":"I'll explain the details to you later.","TWN":"詳細的之後再跟你說明。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그리고 이건 아이기스의 데이터베이스에서 찾아낸 당신의 전술 무장입니다.","JPN":"そしてこれは、アイギスのデータベースから見つけた、あなたの戦術武装です。","ENG":"And this is your Tactical Gear that I found within the database of Aegis.","TWN":"另外，我從埃癸斯的資料庫裡發現了你的戰術裝備。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"전술 무장?","JPN":"戦術武装？","ENG":"Tactical Gear?","TWN":"戰術裝備？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"간단히 말하면, 다른 세계의 당신이 쓰던 무기라고 생각하면 됩니다.","JPN":"簡単に言えば、別の世界のあなたが使っていた武器です。","ENG":"Think of it as the weapon the \\"you\\" from another world used.","TWN":"簡單來說，就是其他世界的你曾使用過的裝備。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"뭐야, 아이기스의 데이터베이스에 정보가 남아 있다는 건, 이런 꼬맹이도 마스터의 세계에서는 델타 세븐이었다는 소리잖아?","JPN":"何だ、アイギスのデータベースに情報が残ってるってことは、こんなガキでもマスターの世界ではデルタセブンだったってことなのか？","ENG":"What? If she's in the database of Aegis, that means this kid was also a member of Delta Seven in Master's world.","TWN":"什麼？埃癸斯的資料庫裡有她的資訊，也就是說這個小不點在大姊的世界裡也是第七三角洲部隊的一員？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"어이, 소령. 이 멍청하게 생긴 얼간이는 또 누구야? 뭔데, 대원복을 입고 있는 거야?","JPN":"ちょっと、少佐。このあほっ面は誰なの？　なんで、制服を着ているのよ？","ENG":"Hey, Major. Who's this stupid-faced jerk? Why's she wearing our uniform?","TWN":"喂，少校。這個長得一臉呆樣的傢伙是誰？怎麼，你也要當我們的隊員？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"뭐라고! 한입거리 꼬맹이 주제에 건방지게! 말 다했냐!","JPN":"んだと！　ちっこいガキのくせに生意気な！　もっかい言ってみろ！","ENG":"What did you just say to me, you little punk?!","TWN":"你說什麼！嘴巴放乾淨點，小不點！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"자, 자~ 다들 좀만 참으세요.","JPN":"はいはい～皆さん、ちょっと辛抱してくださいね。","ENG":"Okay, okay. Hold on to your horses, all right?","TWN":"好了，好了～大家都少說二句。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"어차피 조금만 있으면 싸움은 질리도록 하게 될 테니까요.","JPN":"どうせもう少ししたら、飽きるほど喧嘩できますからね。","ENG":"We'll be fighting to our heart's content in a bit anyway.","TWN":"想打架的話，等下盡情打個夠。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"어, 얼라리? 능구렁이 너……?","JPN":"あ、あれれ？　狸、アンタ……？","ENG":"H-huh? Smirky, is that you...?","TWN":"嗯嗯嗯？你，你，你是……？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"안 그래요? 카린 양?","JPN":"そうですよね？　カリンさん？","ENG":"Isn't that right, Karin?","TWN":"我說的沒錯吧？卡琳？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"아니, 이제는 카린 웡 소령님이라고 불러드려야 하나?","JPN":"あ、そうか。これからはカリン・ウォン少佐って呼ばないといけないんでしたっけ？","ENG":"Or do I have to call you Major Karin Wong now?","TWN":"不對，現在應該叫你卡琳少校？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"대원복, 잘 어울리네요. 시영 씨.","JPN":"制服、お似合いですよ。シノンさん。","ENG":"You look good in that uniform, Shiyoung.","TWN":"這個隊服很適合你，時雨。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"파렴치 한 건 여전하지만.","JPN":"破廉恥なのは相変わらずですが。","ENG":"Though you still look vulgar.","TWN":"雖然還是那麼厚臉皮。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"하핫, 카린 양이 그렇게 말해주니 고마운데요?","JPN":"ははっ、カリンさんにそう言ってもらえると嬉しいですね！","ENG":"Ha hah, that means a lot coming from you, Karin.","TWN":"哈哈，聽卡琳這麼說，我很感謝呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"전 대원, 지금부터 제3 차 아포리아 공략 작전 브리핑을 시작하겠습니다.","JPN":"隊員の皆さん、ただいまより第3次アポリア攻略作戦の事前説明を開始します。","ENG":"All units, the briefing for Operation Aporia 3rd attempt will start now.","TWN":"全體隊員，現在開始，開始進行第3波阿波利亞作戰說明。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"작전의 개요는 심플합니다.","JPN":"作戦の概要はシンプルです。","ENG":"The plan is simple.","TWN":"作戰計畫很簡單。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"먼저, 현 방위선에서 아포리아의 침식체 군세를 상대로 방어전을 펼치는 사이.","JPN":"まず、本防衛線にてアポリアの侵食体軍勢を相手に防衛戦を繰り広げている間。","ENG":"First, while we defend against Aporia's army of C.O.s at the current Defense Line,","TWN":"首先，在目前防線與阿波利亞的侵蝕體軍團展開防禦戰。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"주시영 결사 대원과 제가 단숨에 침식체 군세의 후위까지 돌입.","JPN":"アキヤマ・シノン決死隊員と私が、一気に侵食体軍勢の後方まで突入し。","ENG":"Joo Shiyoung and I will infiltrate into their backlines.","TWN":"同時，周時雨隊員和我會一舉攻入侵蝕體後方。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"제가 단독으로 아포리아와 교전.","JPN":"私がアポリアと単独で交戦。","ENG":"I will fight Aporia on my own.","TWN":"我將單獨與阿波利亞進行交戰。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"방어전을 마친 본대가 교전에 합류하여 아포리아를 격파합니다.","JPN":"その間、防衛戦を終わらせた本隊が戦いに合流し、アポリアを撃破します。","ENG":"Once the Defense Line is secured, the main forces will join me to defeat Aporia.","TWN":"之後完成防禦戰的大部隊將會加入交戰，一同擊破阿波利亞。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"자, 잠깐! 시작부터 터무니없는 소리잖아!","JPN":"ちょ、ちょっと待って！　始めっから無茶苦茶じゃない！","ENG":"W-wait! This is ridiculous from the start!","TWN":"等，等一下！沒頭沒尾地在說什麼！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"시뮬레이터에 확인된 대형 3종만 수백 마리가 넘어! 고작 이 병력으로는 못 막는다고!","JPN":"シミュレーターで確認された大型3種だけでも数百体を超えてるのよ！　この程度の兵力じゃ防げないわよ！","ENG":"Just counting the large Category 3 C.O.s, the simulator has confirmed hundreds of them! We can't fend them all off with these few troops!","TWN":"光是模擬器確認到的大型3類侵蝕體就超過數百隻！就我們這點兵力怎麼擋得住！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"아니요, 제가 아포리아를 맡는 동안, 아이기스는 방어전을 펼치는 본대를 화력 지원합니다.","JPN":"いいえ、私がアポリアの相手をしている間、アイギスは防衛戦を繰り広げる本隊に火力支援を行います。","ENG":"No, while I deal with Aporia, Aegis will provide fire support for the main forces.","TWN":"不會的，在我與阿波利亞對峙期間，埃癸斯會為進行防禦戰的部隊提供火力支援。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"아이기스의 화력과 여러분의 전술 무장이 있다면, 불가능한 일은 아니에요.","JPN":"アイギスの火力と皆さんの戦術武装があれば、不可能ではありません。","ENG":"With the firepower of Aegis and your Tactical Gear, it's not entirely impossible.","TWN":"有埃癸斯的火力和各位的戰術裝備，是有可能的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"함선의 공간 도약이 없으면, 아포리아가 있는 후위까지 어떻게 접근할 건데?","JPN":"艦船の空間跳躍なしに、どうやってアポリアがいる後方にまで接近するつもり？","ENG":"Without the ship's space jump, how do you plan on going to the backlines where Aporia is?","TWN":"可是沒有艦船的空間跳躍，你要怎麼接近阿波利亞所在的後方？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"걸어서 갈 건 아니잖아!","JPN":"歩いていくわけじゃないわよね？","ENG":"It's not like you can just walk all the way over there!","TWN":"總不能走過去吧！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"거기서 제가 나설 차례인 거죠, 엣헴!","JPN":"そこで私の出番なんですっ、えっへん！","ENG":"That's where I come into play. Ahem!","TWN":"嗯嘿，這就要看我的了！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"능구렁이?","JPN":"狸？","ENG":"Smirky?","TWN":"靠你這個老油條？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"시영 씨에 대한 기록은 아이기스 무기고 데이터베이스에 없었지만…….","JPN":"シノンさんについての記録はアイギスの武器庫データベースにはありませんでしたが……","ENG":"Although there is no record of Shiyoung in Aegis's database...","TWN":"雖然埃癸斯武器庫的資料庫沒有時雨的記錄……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"대신, 시영씨의 능력과 호환이 가능한 공간 능력자의 전술 무장은 확보할 수 있었어요.","JPN":"その代わり、シノンさんの能力とマッチする空間能力者の戦術武装を確保することができました。","ENG":"We were still able to secure the Tactical Gear of another space manipulator that's compatible with her abilities.","TWN":"但有找到與時雨能力相符的空間能力者戰術裝備。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그 공간 돌파 슈트가 있다면, 단거리 공간 도약을 반복해서 함선처럼 빠르게 적의 후위로 절 데려다 줄 수 있을 거예요.","JPN":"その空間突破スーツがあれば、短距離の空間跳躍を繰り返し、艦船のように素早く私を敵の後方にまで連れていけるはずです。","ENG":"With this spatial breakthrough suit, she'll be able to take me to the back of the enemy lines with repeated short-distance space jumps.","TWN":"只要有那套裝備，再透過反復進行近距空間跳耀，她就可以像艦船一樣快速將我帶至敵人的後方。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"하핫, 그렇게 말하니까 마치 인간 함선, 주시영함이 된 것 같은데요?","JPN":"ハハッ、そうまで言われるとまるで人間艦船アキヤマ・シノン艦になった気分ですね！","ENG":"Ha hah, that makes me sound like I'm some kind of human-ship.","TWN":"哈哈，這麼一說，感覺自己像是人型艦船似的，是時雨艦嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그래. 뭐, 다 좋다 이거야.","JPN":"あっそ。わかった、わかった。","ENG":"Yeah, sure. Let's say that works.","TWN":"嗯，好。暫不說這個問題。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그래서? 소령, 너 혼자 정말 버틸 수 있겠어?","JPN":"それで？　少佐、あなたは本当に一人で持ちこたえられるの？","ENG":"So? Are you sure you can handle it on your own, Major?","TWN":"然後呢？少校，你一個人能撐得住嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"아니, 버텨냈다 쳐도 우리가 정말 쓰러트릴 수 있는 거야?","JPN":"ううん、持ちこたえられたとしても、本当にアタシたちに倒せるの？","ENG":"Even if you were still alive by the time we joined you, do you think we'd be able to defeat it?","TWN":"不，就算能撐下去，你真的能打倒他嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그 5종 침식체, 아포리아를?","JPN":"あの第5種侵食体、アポリアを？","ENG":"A Category 5 C.O.? Aporia?","TWN":"那可是5類侵蝕體，阿波利亞欸？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"할 수 있느냐의 문제가 아니에요.","JPN":"できるかどうかの問題じゃありません。","ENG":"It's not about whether it can be done or not.","TWN":"這不是能不能辦到的問題。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"우리에겐 반드시 아포리아를 쓰러트려야 하는 의무가 있습니다.","JPN":"私たちには必ずアポリアを倒さなければならない、義務があります。","ENG":"We have a duty to defeat Aporia, whatever it takes.","TWN":"對於我們來說，有著一定要打敗阿波利亞的義務。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"왜냐하면 5종 침식체 아포리아의 정체는……","JPN":"なぜなら第5種侵食体アポリアの正体は……","ENG":"Because the identity of the Category 5 C.O. Aporia is...","TWN":"因為，5類侵蝕體阿波利亞的原身是……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"크로스로드 작전에서 전사했던 제이크 워커 대령님의 그림자이기 때문입니다.","JPN":"クロスロード作戦で戦死したジェイク・ウォーカー大佐のシャドウだからです。","ENG":"Colonel Jake Walker who died during Operation Crossroads, and is now a Shadow.","TWN":"在十字路口作戰中戰死的傑克·沃克上校。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"그림자? 아포리아가 그림자였단 말이야?","JPN":"シャドウ？　アポリアがシャドウだったって？","ENG":"A Shadow? You mean Aporia is a Shadow?","TWN":"暗影？阿波利亞？原來是暗影嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"워커 대령님이라면, 설마 크로스로드 작전에서……!","JPN":"ウォーカー大佐って、まさかクロスロード作戦で……！","ENG":"Colonel Walker? From Operation Crossroads...?!","TWN":"沃克上校的話，難道是十字路口作戰中……！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"말도 안 돼. 어떻게 그런 끔찍한 일이.","JPN":"嘘だろ。どうしてそんなことが。","ENG":"That's insane. How could something so horrible happen...?","TWN":"怎麼可能？怎麼會有那麼可怕的事情。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이 작전에서 우리가 아포리아를 쓰러트리지 못한다면.","JPN":"この作戦で私たちがアポリアを倒すことができなかったら。","ENG":"If we fail to defeat Aporia this time...","TWN":"這次作戰我們無法將阿波利亞打敗的話。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"제이크 대령님은 지금껏 자신이 지켜낸 세계를 자신의 손으로 부수게 될 겁니다.","JPN":"ウォーカー大佐はこれまで自分が守ってきた世界を、自分の手で壊すことになります。","ENG":"Colonel Walker will destroy the very world he saved with his own hands.","TWN":"上校就將親手摧毀自己守護至今的世界。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"델타 세븐의 전우로서, 그를 동경해온 대원으로서 전 그걸 결단코 용납할 수 없습니다.","JPN":"デルタセブンの戦友として、彼に憧れてきた隊員として、私は決してそれを許せません。","ENG":"As a Delta Seven comrade and someone who respected him, I will not let that happen.","TWN":"作為第七三角洲部隊的戰友，作為一名敬重他的隊員，我絕對不能容忍那個結果。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그러니까 전 대원, 부디 힘을 빌려주세요.","JPN":"ですから全隊員は、どうか力を貸してください。","ENG":"So, all units, please lend me your strength.","TWN":"所以全體隊員，請務必將你們的力量借給我。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"후후, 이거 카린 양의 데이트 때문에 여러 사람들이 고생하겠는데요?","JPN":"ふふ、これはカリンさんとのおデートで、色んな人が苦労しそうですね？","ENG":"Heh heh, guess your little date is going to make a lot of people suffer.","TWN":"呵呵，我猜為了卡琳的約會，很多人都會很辛苦吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"하지만 보내 드려야겠죠. 원래 죽은 사람은 여기 있으면 안 되는 거잖아.","JPN":"でも成仏させてあげないとですよね。ここは死者のいる場所じゃありませんから。","ENG":"But I have to send him off. The dead should stay dead.","TWN":"但我們必須送走他。死去的人就該讓他安息才對。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"……고마워요, 시영 씨.","JPN":"……ありがとうございます、シノンさん。","ENG":"...Thank you, Shiyoung.","TWN":"……謝謝你，時雨。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"소령, 난 아직 당신이 그다지 마음에 들진 않아.","JPN":"少佐、オレはまだお前が気にくわない。","ENG":"Major, I still have my doubts about you.","TWN":"我還是不太喜歡你，少校。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"하지만 내 목숨을 살려준 마스터는 죽기 전에 당신을 따르라고 했어.","JPN":"でもオレの命を救ってくれたマスターはお前について行けと言った。","ENG":"But Master, who saved my life, told me to follow you as her dying wish.","TWN":"但大姊救過我的命，她死之前讓我跟著你。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"그러니 도와주지. 마스터를 위해, 그리고 나 스스로를 위해.","JPN":"だから手を貸す。マスターのために、そして自分自身のために。","ENG":"So I'll help you. For Master's sake and mine.","TWN":"所以也只能幫忙了，為了大姊，也為了我自己。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"아으……! 알았어! 하면 되잖아, 하면!","JPN":"もう……！　わかったわよ！　やればいいんでしょ、やれば！","ENG":"Ugh...! Fine! I'll do it, okay?","TWN":"呃呃……！好啦！做就做！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"난 이런 닭살 분위기 진짜 싫더라……!","JPN":"こういう感動的な雰囲気って鳥肌が立つのよ……！","ENG":"I hate these cringe moments...!","TWN":"我真的很討厭這種肉麻的氣氛……！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"두 사람, 모두 제 고집에 응해주셔서 감사합니다.","JPN":"二人とも、私のわがままに付き合ってくれてありがとうございます。","ENG":"Thank you both for tolerating my stubbornness.","TWN":"謝謝你們二個願意遷就我的固執。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그건 그렇다 쳐도 그 의안, 정말로 괜찮겠어?","JPN":"それはそうと、その義眼は本当に大丈夫なのか？","ENG":"Besides that, are you sure you'll be okay with that glass eye?","TWN":"不過，那個義眼真的沒問題嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"원래 의체라는 건 굉장히 섬세한 물건이야.","JPN":"本来義体っていうのはすごく繊細なものなんだ。","ENG":"Prosthetics are extremely delicate objects.","TWN":"本來義肢就是非常精細的東西。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"동조율이라는 게 있어서 사람에 따라 맞춤 제작이 필요하다고.","JPN":"同調率というものがあって、個人個人に合わせて製作するのが基本なんだ。","ENG":"There's something called synchronization that requires them to be custom-made for each person.","TWN":"因為涉及同步率，每個人都需要量身定做。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"내가 집도하긴 했지만, 의체가 기계 부품처럼 막 갈아 끼운다고 되는 게 아니라니까.","JPN":"僕が執刀しはしたけど、義体は機械の部品みたいに単につければどうにかなるってものじゃない。","ENG":"Even though I performed the transplant, prosthetics aren't as simple as switching out machine parts.","TWN":"雖然是我操刀製作的，但義肢不像機器零件一樣可以隨便更換。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"게다가 함선이랑 정신을 잇는다는 게 나는 무슨 소리인지 아직도 감이 안 와.","JPN":"それに、艦船と精神を繋げるって、僕には仕組みが全く想像もつかないよ。","ENG":"Also, I still don't understand the whole connected-to-the-ship nonsense.","TWN":"而且，我也還無法理解和艦船意識相通是什麼感覺。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어떤 부작용이 있을지, 신경에 어떤 부담을 줄지 전혀 알 수 없다고.","JPN":"どんな副作用があって、神経にどんな負担がくるか全くわからないんだ。","ENG":"There's no telling what kind of side effect you'll have or how it will affect your senses.","TWN":"完全不知道會產生什麼副作用，會對精神造成什麼樣的負擔。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"의안의 동조율이라면, 걱정하지 마세요, 박사님.","JPN":"義眼の同調率なら、大丈夫ですよ、博士。","ENG":"You don't have to worry about the synchronization issue, Doctor.","TWN":"若是義眼的同步率，那你不用擔心，博士。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"<color=#ffd34c>그자</color>가 했는데, <color=#ffd34c>제</color>가 못할 리 없으니까요.","JPN":"<color=#ffd34c>あの人</color>にできて、<color=#ffd34c>私</color>にできないはずがないですから。","ENG":"It worked for <color=#ffd34c>her</color>, so it'll work for <color=#ffd34c>me</color> too.","TWN":"因為<color=#ffd34c>她</color>能做的，<color=#ffd34c>我</color>也都能做。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"우선은 이 작전을 성공적으로 끝내는 것에만 집중하도록 해요.","JPN":"まずは今回の作戦を無事やり遂げることだけに集中してください。","ENG":"Right now, we should focus on successfully ending this operation.","TWN":"我們先把精力集中在如何成功完成這次作戰上吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"소령님, 이걸 받아 주셨으면 합니다.","JPN":"少佐、これを受け取ってください。","ENG":"Major, I want you to take these.","TWN":"少校，請你收下這個。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"What is all this...?","TWN":"這是……？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"방위군의 오랜 풍습이거든요.","JPN":"防衛軍の古くからのならわしなんです。","ENG":"It's an old custom of the Defense Force.","TWN":"這是保衛軍長久以來的習俗。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"저희가 가지고 있는 잡동사니들을 모아봤습니다.","JPN":"私たちがそれぞれ持っているものを集めてみました。","ENG":"We gathered some oddments that we had.","TWN":"這些都是我們隨身攜帶的小東西。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"작전이 끝나고 나면, 살아남은 사람이 그걸 모아서 유족에게 전달해주는 거죠.","JPN":"作戦が終わったら、生き残った者がそれを遺族に届けるんです。","ENG":"Once an operation ends, those still alive will deliver them to the fallen comrades' families.","TWN":"作戰結束後，活下來的人會將這些收集起來轉交給遺屬。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이 유품을 전달하기 위해서라도, 반드시 살아남으라는 뜻이로군요.","JPN":"この遺品を届けるためにも、必ず生き残れという意味なんですね。","ENG":"You want me to return alive to at least deliver these mementos.","TWN":"這是希望我……一定要活下去，把這些東西轉交給給遺屬的意思？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"하하, 유품이라고 하면 너무 거창해지니까, 그냥 부적 정도라고 생각해주십시오.","JPN":"はは、遺品というのは大袈裟です、お守りぐらいに思っておいてください。","ENG":"Ha ha, they aren't anything special enough to be mementos. Just think of them as charms.","TWN":"哈哈，說是遺物也太誇張了，你就當作是護身符吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"반드시 살아남아주세요, 소령님.","JPN":"必ず生き残ってください、少佐。","ENG":"Please make it back in one piece, Major.","TWN":"請你一定要收下，少校。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"전 대원, 모두 감사합니다.","JPN":"隊員の皆さん、ありがとうございます。","ENG":"Thank you, all.","TWN":"全體隊員，謝謝你們。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이 작전에는 우리 세계의 운명이 달려 있습니다.","JPN":"この作戦には私たちの世界の運命がかかっています。","ENG":"The fate of our world rests in this operation.","TWN":"這次作戰關係到我們世界的命運。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이번에는…… 이번에야말로 반드시 작전을 성공시켜 함께 내일의 풍경을 마주하도록 해요.","JPN":"今回は……今度こそ必ず作戦を成功させて、共に明日を迎えましょう。","ENG":"This time... We will successfully complete the operation and greet tomorrow's sun together.","TWN":"這次……這次我們一定會成功，一同迎接明天的風景。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};